solutions.cpp:
#include <iostream>
#include <string>

class Solution {
public:
	bool solve(const std::string &s1, const std::string &s2) {
		return s1 == s2;
	}
};

int main() {
	std::string s;
	std::cin >> s;
	std::string s1, s2;
	std::istringstream iss(s);
	iss >> s1 >> s2;
	Solution sol;
	std::cout << std::boolalpha << sol.solve(s1, s2) << std::endl;
	return 0;
}
